    /**
     * Get the inline SVG for a provider.
     */
    public static function svg(string $provider): ?string
    {
        return self::ICONS[$provider] ?? null;
    }

    /**
     * Get available button styles for a provider.
     *
     * @return array<string, array{label: string, bg: string, text: string, border: string, icon: string}>|null
     */
    public static function styles(string $provider): ?array
    {
        return self::STYLES[$provider] ?? null;
    }

    /**
     * Get a specific button style for a provider.
     *
     * @return array{label: string, bg: string, text: string, border: string, icon: string}|null
     */
    public static function style(string $provider, string $variant): ?array
    {
        return self::STYLES[$provider][$variant] ?? null;
    }

    /**
     * Get the default style variant name for a provider.
     */
    public static function defaultStyle(string $provider): ?string
    {
        $styles = self::STYLES[$provider] ?? null;

        return $styles !== null ? array_key_first($styles) : null;
    }

    /**
     * Get the brand color for a provider (first style variant).
     *
     * @return array{bg: string, text: string, border: string, icon: string}|null
     */
    public static function brandColor(string $provider): ?array
    {
        $styles = self::STYLES[$provider] ?? null;
        if ($styles === null) {
            return null;
        }

        /** @var array{bg: string, text: string, border: string, icon: string} */
        return reset($styles);
    }

    /**
     * Check if an icon exists for a provider.
     */
    public static function has(string $provider): bool
    {
        return isset(self::ICONS[$provider]);
    }

    /**
     * Get all available provider names.
     *
     * @return list<string>
     */
    public static function providers(): array
    {
        return array_keys(self::ICONS);
    }
}
